module RefModule(clk, WE, RE, din, dout);  
    input clk;  
    input WE;  
    input RE;  
    input [3:0] din;  
    output reg [3:0] dout;  
    reg [3:0] storage;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (WE) begin  
            storage <= din;  
        end  
        if (RE) begin  
            dout <= storage;  
        end  
    end  
endmodule
